-- ============================================
-- 博客数据库 PostgreSQL 兼容数据导入脚本
-- ============================================

-- 1. 禁用所有外键约束检查（PostgreSQL 方式）
SET session_replication_role = 'replica';

-- 2. 清空现有表数据（确保干净且不冲突）
TRUNCATE TABLE comment_likes, article_likes, comments, articles, collections, photos, profiles, users RESTART IDENTITY CASCADE;

-- ----------------------------
-- 插入 users 表数据
-- ----------------------------

-- ----------------------------
-- 插入 collections 表数据
-- ----------------------------

-- ----------------------------
-- 插入 articles 表数据
-- ----------------------------

-- ----------------------------
-- 插入 comments 表数据
-- ----------------------------

-- ----------------------------
-- 插入 article_likes 表数据
-- ----------------------------

-- ----------------------------
-- 插入 comment_likes 表数据
-- ----------------------------

-- ----------------------------
-- 插入 profiles 表数据
-- ----------------------------

-- 3. 恢复外键约束检查
SET session_replication_role = 'origin';

-- 4. 更新 ID 序列（防止之后插入数据时 ID 冲突）
SELECT setval('users_id_seq', (SELECT MAX(id) FROM users));
SELECT setval('collections_id_seq', (SELECT MAX(id) FROM collections));
SELECT setval('articles_id_seq', (SELECT MAX(id) FROM articles));
SELECT setval('comments_id_seq', (SELECT MAX(id) FROM comments));
SELECT setval('article_likes_id_seq', (SELECT MAX(id) FROM article_likes));
SELECT setval('comment_likes_id_seq', (SELECT MAX(id) FROM comment_likes));
SELECT setval('profiles_id_seq', (SELECT MAX(id) FROM profiles));
